// These are template strings for generated hook scripts.
// They are written to disk as standalone Node.js scripts, not executed in this process.
// The use of execSync in templates is intentional for git hook runners.

export const RUNNER_TEMPLATE = `#!/usr/bin/env node
// Codi pre-commit hook runner
// Auto-generated by codi init

const { execSync } = require('child_process');

const hooks = {{HOOKS_JSON}};

function getStagedFiles(filter) {
  try {
    const output = execSync('git diff --cached --name-only --diff-filter=ACMR', { encoding: 'utf-8' });
    const files = output.trim().split('\\n').filter(Boolean);
    if (!filter) return files;
    const re = new RegExp(filter.replace(/\\*\\*/g, '.*').replace(/\\*/g, '[^/]*'));
    return files.filter(f => re.test(f));
  } catch { return []; }
}

let exitCode = 0;
for (const hook of hooks) {
  const files = getStagedFiles(hook.stagedFilter);
  if (files.length === 0) continue;
  console.log(\`Running \${hook.name}...\`);
  try {
    execSync(\`\${hook.command} \${files.join(' ')}\`, { stdio: 'inherit' });
  } catch (e) {
    console.error(\`\${hook.name} failed\`);
    exitCode = 1;
  }
}
process.exit(exitCode);
`;

export const SECRET_SCAN_TEMPLATE = `#!/usr/bin/env node
// Codi secret scanner
const fs = require('fs');

const PATTERNS = [
  /(?:api[_-]?key|apikey)\\s*[:=]\\s*['"][^'"]{8,}/i,
  /(?:secret|password|passwd|pwd)\\s*[:=]\\s*['"][^'"]{8,}/i,
  /(?:token|bearer)\\s*[:=]\\s*['"][^'"]{8,}/i,
  /-----BEGIN (?:RSA |EC |DSA )?PRIVATE KEY-----/,
  /ghp_[a-zA-Z0-9]{36}/,
  /sk-[a-zA-Z0-9]{32,}/,
];

const files = process.argv.slice(2);
let found = false;
for (const file of files) {
  try {
    const content = fs.readFileSync(file, 'utf-8');
    for (const pattern of PATTERNS) {
      if (pattern.test(content)) {
        console.error(\`Potential secret found in \${file}\`);
        found = true;
        break;
      }
    }
  } catch {}
}
if (found) process.exit(1);
`;

export const VERSION_CHECK_TEMPLATE = `#!/usr/bin/env node
// Codi version and freshness checker
// Auto-generated by codi init

const { execFileSync } = require('child_process');

try {
  execFileSync('npx', ['codi', 'doctor', '--ci'], { stdio: 'inherit' });
} catch (e) {
  process.exit(1);
}
`;

export const FILE_SIZE_CHECK_TEMPLATE = `#!/usr/bin/env node
// Codi file size checker
const fs = require('fs');

const maxLines = {{MAX_LINES}};
const files = process.argv.slice(2);
let failed = false;
for (const file of files) {
  try {
    const content = fs.readFileSync(file, 'utf-8');
    const lines = content.split('\\n').length;
    if (lines > maxLines) {
      console.error(\`\${file}: \${lines} lines (max: \${maxLines})\`);
      failed = true;
    }
  } catch {}
}
if (failed) process.exit(1);
`;
